// tests/integration/close_tests.rs
#[test]
fn test_close_basic() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");
    let id = create_issue(&beads_dir, "Issue to close");

    br_cmd(&beads_dir)
        .args(["close", &id])
        .assert()
        .success()
        .stdout(predicate::str::contains("Closed"));

    // Verify status is closed
    br_cmd(&beads_dir)
        .args(["show", &id, "--json"])
        .assert()
        .stdout(predicate::str::contains("\"status\":\"closed\""));
}

#[test]
fn test_close_with_reason() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");
    let id = create_issue(&beads_dir, "Issue with reason");

    br_cmd(&beads_dir)
        .args(["close", &id, "--reason", "Feature completed"])
        .assert()
        .success();

    // Verify reason is stored
    let output = br_cmd(&beads_dir)
        .args(["show", &id, "--json"])
        .output()
        .unwrap();
    let json: Value = serde_json::from_slice(&output.stdout).unwrap();
    assert_eq!(json[0]["close_reason"], "Feature completed");
}

